insert into public.buildings (id, name_ar, name_en, description_ar, description_en, type, latitude, longitude, address_text, is_accessible, is_active) values
('b1111111-1111-1111-1111-111111111111', 'كلية علوم الحاسب والمعلومات', 'College of Computer Science and Information', 'كلية علوم الحاسب تقع في المنطقة الشمالية للحرم الجامعي، مجهزة بالكامل بالمنحدرات والمصاعد المخصصة ومسارات المكفوفين.', 'The computer science college is located in the northern sector. It is fully accessible with ramps, tactile paths, and elevators.', 'college', 24.7136, 46.6753, 'شمال الحرم الجامعي، بجوار كلية الهندسة', true, true),
('b2222222-2222-2222-2222-222222222222', 'كلية الهندسة', 'College of Engineering', 'كلية الهندسة، مبنى رقم 3، يحتوي على مداخل مهيأة عند البوابات الغربية والشرقية.', 'College of Engineering, Building 3, features accessible entrances at western and eastern gates.', 'college', 24.7142, 46.6765, 'شمال الحرم الجامعي، بجوار مواقف السيارات رقم 4', true, true),
('b3333333-3333-3333-3333-333333333333', 'كلية العلوم', 'College of Science', 'كلية العلوم، مبنى رقم 4. يحتوي على مصاعد مهيأة ناطقة لخدمة ضعاف البصر والمكفوفين.', 'College of Science, Building 4. Features talking elevators for visually impaired users.', 'college', 24.7121, 46.6741, 'وسط الحرم الجامعي، بجوار المكتبة', true, true),
('b4444444-4444-4444-4444-444444444444', 'عمادة شؤون الطلاب', 'Deanship of Student Affairs', 'مبنى عمادة شؤون الطلاب مجهز بالكامل للمراجعين، مع ممرات أرضية بارزة وتوجيهات واضحة.', 'The Deanship building is fully accessible with tactile flooring and voice guidance systems.', 'deanship', 24.7105, 46.6722, 'المنطقة الإدارية، بجوار البوابة الرئيسية', true, true),
('b5555555-5555-5555-5555-555555555555', 'المكتبة المركزية', 'Central Library', 'المكتبة المركزية، تحتوي على طابق أرضي مهيأ لخدمة ذوي الإعاقة وغرف للقراءة بالصوت وبرايل.', 'Central Library, featuring accessible ground floor reading rooms and Braille support.', 'library', 24.7118, 46.6735, 'وسط الحرم الجامعي', true, true),
('b6666666-6666-6666-6666-666666666666', 'مبنى السنة التحضيرية', 'Preparatory Year Building', 'مبنى السنة التحضيرية للطلاب الجدد، مجهز بالكامل بمسارات حركة آمنة ومنحدرات ومصاعد.', 'Preparatory Year Building, fully equipped with safe pathways, accessibility ramps and lifts.', 'college', 24.7090, 46.6710, 'المنطقة الجنوبية للحرم الجامعي', true, true);
insert into public.floors (id, building_id, floor_number, name_ar, name_en) values
('f1111111-1111-1111-1111-111111111111', 'b1111111-1111-1111-1111-111111111111', 0, 'الدور الأرضي', 'Ground Floor'),
('f2222222-2222-2222-2222-222222222222', 'b1111111-1111-1111-1111-111111111111', 1, 'الدور الأول', 'First Floor');
insert into public.navigation_points (id, building_id, floor_id, name_ar, name_en, type, latitude, longitude, indoor_x, indoor_y, description_ar, description_en, audio_instruction_ar, audio_instruction_en, is_accessible, is_hazard, is_active) values
('p0000000-0000-0000-0000-000000000000', null, null, 'بوابة الحرم الرئيسية', 'Main Campus Gate', 'entrance', 24.7082, 46.6705, null, null, 'البوابة الخارجية الرئيسية للحرم الجامعي المخصصة للمشاة.', 'The main pedestrian entrance gate of the university campus.', 'أنت الآن عند بوابة الحرم الرئيسية. انطلق للأمام نحو الممشى الرئيسي.', 'You are at the main campus gate. Proceed straight along the main walkway.', true, false, true),
('p0000000-0000-0000-0000-000000000001', null, null, 'التقاطع الرئيسي للمشاة', 'Main Pedestrian Intersection', 'intersection', 24.7100, 46.6720, null, null, 'تقاطع ممرات المشاة الذي يربط البوابة بكلية الحاسب والمكتبة.', 'A pedestrian crossway linking the main gate, CS building, and the Library.', 'تقاطع رئيسي. للأمام نحو المكتبة، لليسار نحو كلية الحاسب والعلوم.', 'Main intersection. Straight for Library, left for CS and Science.', true, false, true),
('p1111111-1111-1111-1111-111111111001', 'b1111111-1111-1111-1111-111111111111', 'f1111111-1111-1111-1111-111111111111', 'منحدر مدخل كلية الحاسب', 'CS Entrance Ramp', 'ramp', 24.7132, 46.6749, 0.0, 0.0, 'المنحدر المؤدي لمدخل الكلية لتجنب السلالم.', 'The accessibility ramp at the entrance of CS to bypass the stairs.', 'منحدر مدخل كلية الحاسب. يقع على يسار الدرج مباشرة ومزود بمسار لمسي.', 'The computer science entrance ramp. Located to the left of the stairs with tactile lines.', true, false, true),
('p1111111-1111-1111-1111-111111111002', 'b1111111-1111-1111-1111-111111111111', 'f1111111-1111-1111-1111-111111111111', 'الباب التلقائي الرئيسي لكلية الحاسب', 'CS Main Automatic Door', 'entrance', 24.7133, 46.6750, 2.0, 5.0, 'البوابة التلقائية الزجاجية لمدخل كلية الحاسب.', 'The main automatic glass entrance door for the CS college.', 'الباب التلقائي الرئيسي لكلية الحاسب. الباب يفتح تلقائيًا بمجرد الاقتراب منه.', 'Main automatic door of CS. It opens automatically as you approach.', true, false, true),
('p1111111-1111-1111-1111-111111111003', 'b1111111-1111-1111-1111-111111111111', 'f1111111-1111-1111-1111-111111111111', 'بهو كلية الحاسب الرئيسي', 'CS Main Lobby', 'corridor', 24.7134, 46.6751, 10.0, 10.0, 'البهو الداخلي الرئيسي لكلية الحاسب، به مسارات تكتيلية صفراء.', 'The inner lobby of CS building, featuring yellow tactile paving floor.', 'بهو الكلية الرئيسي. توجد لوحة الاستعلامات على يمينك والمصاعد في نهاية الممر على اليسار.', 'Main lobby of CS. Help desk is on your right and elevators are at the end of the left corridor.', true, false, true),
('p1111111-1111-1111-1111-111111111004', 'b1111111-1111-1111-1111-111111111111', 'f1111111-1111-1111-1111-111111111111', 'مصعد كلية الحاسب - الدور الأرضي', 'CS Ground Floor Elevator', 'elevator', 24.7135, 46.6752, 10.0, 30.0, 'مصعد ناطق مجهز بأزرار بارزة برايل.', 'A voice-guided elevator equipped with Braille tactile buttons.', 'مصعد الدور الأرضي لكلية الحاسب. أزرار التحكم تقع على يمين فتحة المصعد.', 'CS Ground floor elevator. Controls are on the right side of the elevator gate.', true, false, true),
('p1111111-1111-1111-1111-111111111005', 'b1111111-1111-1111-1111-111111111111', 'f1111111-1111-1111-1111-111111111111', 'دورة المياه المهيأة بكلية الحاسب', 'CS Accessible Restroom', 'restroom', 24.7134, 46.6753, 25.0, 12.0, 'دورة مياه واسعة مجهزة بمساند ومقابض خاصة لذوي الاحتياجات.', 'A spacious restroom with handrails and assistance buttons.', 'دورة المياه المهيأة لكلية الحاسب. الباب يفتح للخارج ويحتوي على قفل عريض.', 'CS accessible restroom. The door opens outward and has a large accessible handle.', true, false, true),
('p1111111-1111-1111-1111-111111111101', 'b1111111-1111-1111-1111-111111111111', 'f1111111-1111-1111-1111-111111111111', 'القاعة الدراسية 101', 'Classroom 101', 'hall', 24.7133, 46.6754, 30.0, 15.0, 'قاعة دراسية في الدور الأرضي بسعة 40 طالبًا.', 'Ground floor classroom with a capacity of 40 students.', 'القاعة 101. الباب يقع على يسار الممر وعليه لوحة برايل البارزة.', 'Classroom 101. The door is on the left side of the corridor and has a Braille placard.', true, false, true),
('p1111111-1111-1111-1111-111111111102', 'b1111111-1111-1111-1111-111111111111', 'f1111111-1111-1111-1111-111111111111', 'القاعة الدراسية 102', 'Classroom 102', 'hall', 24.7133, 46.6755, 30.0, 20.0, 'قاعة دراسية في الدور الأرضي بجوار القاعة 101.', 'Ground floor classroom next to Classroom 101.', 'القاعة 102. الباب يقع على يسار الممر وعليه لوحة برايل البارزة.', 'Classroom 102. The door is on the left side of the corridor and has a Braille placard.', true, false, true),
('p4444444-4444-4444-4444-444444444001', 'b4444444-4444-4444-4444-444444444444', null, 'مدخل عمادة شؤون الطلاب الرئيسي', 'Student Affairs Main Entrance', 'entrance', 24.7104, 46.6720, null, null, 'المدخل المهيأ الرئيسي لمبنى عمادة شؤون الطلاب.', 'The primary accessible entrance for the Student Affairs Deanship.', 'أنت الآن عند مدخل عمادة شؤون الطلاب. المكاتب بالداخل مباشرة.', 'You are at the student affairs entrance. Offices are directly inside.', true, false, true),
('p5555555-5555-5555-5555-555555555001', 'b5555555-5555-5555-5555-555555555555', null, 'مدخل المكتبة المركزية الرئيسي', 'Central Library Main Entrance', 'entrance', 24.7119, 46.6734, null, null, 'مدخل المكتبة المركزية المهيأ الخالي من العوائق.', 'The accessible, barrier-free entrance of the Central Library.', 'مدخل المكتبة المركزية الرئيسي. ادخل مباشرة نحو بوابات الاستعارة والبهو.', 'Central Library main entrance. Enter directly towards the checkout desks and lobby.', true, false, true);
