('r4444444-4444-4444-4444-444444444444', 'p1111111-1111-1111-1111-111111111003', 'p1111111-1111-1111-1111-111111111005', 'من البهو إلى دورة المياه المهيأة', 'From Lobby to Accessible Restroom', 'wheelchair', 12.0, 0.3, false, false, true, true, 'active');
